class Solution:
    def minOperations(self, nums1, nums2, k):
        n = len(nums1)
        diffs = [nums2[i] - nums1[i] for i in range(n)]
        if k == 0:
            return 0 if all(d == 0 for d in diffs) else -1
        pos = []
        neg = []
        for d in diffs:
            if d % k != 0:
                return -1
            q = d // k
            if q > 0:
                pos.append(q)
            elif q < 0:
                neg.append(-q)
        if sum(pos) != sum(neg):
            return -1
        return sum(pos)

