class Solution:
    def minOperations(self, nums1, nums2, k):
        n = len(nums1)
        diffs = [nums2[i] - nums1[i] for i in range(n)]
        if k == 0:
            return 0 if all(d == 0 for d in diffs) else -1
        total = sum(diffs)
        if total != 0:
            return -1
        ops = 0
        for d in diffs:
            if d % k != 0:
                return -1
            if d > 0:
                ops += d // k
        return ops

