var minOperations = function(nums1, nums2, k) {
    const n = nums1.length;
    if (k === 0) {
        for (let i = 0; i < n; i++) if (nums1[i] !== nums2[i]) return -1;
        return 0;
    }
    let total = 0, ops = 0;
    for (let i = 0; i < n; i++) {
        const d = nums2[i] - nums1[i];
        total += d;
        if (d % k !== 0) return -1;
        if (d > 0) ops += d / k;
    }
    return total === 0 ? ops : -1;
};
